INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07420', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中「豫且之患」，意謂：', '["吳王在與民眾飲酒時，可能受到傷害", "君王喜好飲酒，將助長臣民淫靡風氣", "吳王好酒失政，將引發鄰國趁機入侵", "奸臣虎視眈眈，可能趁機會謀反叛亂 這至今猶會燙傷我的沸煙竟是五十萬年前的餘燼嗎？ 不能解，不可解，不必有解。 一路走下步道，雲簇霧湧之上自有麗日藍天，那藍一碧無瑕，亮潔得近乎數學──對，就是數學的 殘忍無情和絕對。但我猶豫了一下，發覺自己竟喜歡這份純粹決絕，那擺脫一切拒絕一切的百分之百全 然正確無誤的高高危危的藍。相較於山的歷劫成灰，天空彷彿是對聯的另一句，無形無質無怒無嗔。 穿出密密的箭竹林，山迴路轉，回頭再看，什麼都不在了。想起有一次在裱畫店裡看到畫家寫的兩 句話：「雲為山骨格，苔是石精神。」而大屯行腳之餘我所想到的卻是：「雲為山綺想，苔是石留言。」 至於那源源地熱，又是山的什麼呢？大約可當作死火山一段亦甜蜜亦悲愴的懺情錄來看吧？（張曉風 〈動情二章〉） 請依上文回答19至20題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07421', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '依據文意推論，作者認為火山地熱的特質是：', '["殘忍無情", "純粹決絕", "無形無質", "有怒有嗔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07422', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '依本文所述，下列選項何者正確？', '["沸煙無形無質", "數學多情猶豫", "當時晴空澄碧", "山容亮潔可愛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07423', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列對於1800年代末期成立的睦鄰中心（settlement houses）之敘述何者正確？', '["教導居民英文、衛生與職業技能", "睦鄰中心的工作人員多居住在郊區，經常需往返通車至城市中心的貧民區工作", "強調個人諮商，就是我們後來通稱的個案工作之基礎", "著名領導人物為John Griscom，積極促使伊利諾州禁止兒童受僱於惡劣環境的小工廠"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07424', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1930年代，美國的大蕭條之後，促使聯邦政府提出社會安全法案（Social Security Act），奠定美國當前 社會福利基礎，請問該法案於西元幾年提出？', '["1932", "1933", "1934", "1935"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07425', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '災難社會工作日益受到重視，在2007年美國社會工作教育委員會（CSWE）已提出災難管理與社會工作 新課程供參考開設，其中社會工作者在救援工作中的七項工作任務，以下何者錯誤？', '["在災難發生前後、救援中、復原後，都應將人們的文化多樣性納入考量", "開發個人、地方、組織、區域、國家，以至於跨國的災難管理策略", "建立災難宣導系統，主動宣導防災教育及物資募集", "以知識與技巧回應災難與創傷事件，以降低受災者的苦痛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07426', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關幾個社會工作理論及其主要理論發展者的配對，何者為正確？', '["生態觀點（ecological perspectives），Alfred Adler", "任務中心取向（task-centered approach），Ross V. Spect", "人本主義觀點（humanist perspectives），Howard Goldstein", "系統理論（system theory），Martin Rein"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07427', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近年來，因案主問題情況的錯綜複雜，社會工作在實務運用上出現折衷主義（eclecticism）的主張，主張 可以在實務上結合不同單一理論給予案主協助，以下有關 Epstein（1992）提出的折衷主義五大模式，何 者錯誤？', '["證據基礎整合模式（evidence-based integration model）", "實務建構模式（constructed personal practice model）", "系統整合模式（systematic integration model）", "偶然使用模式（casual application model）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07428', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關 Saleeby（1992）對優勢觀點（strengths perspective）的敘述，何者正確？①尊重案主的優勢', '["社會工作者是案主的啟發者", "案主必定具有優勢之處", "案主的行動需基植於其所有擁有的優勢 ⑤任何環境中都具有可用的資源", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07429', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當機構為了生存及維持運作的需要，要求社會工作者暫時放下服務案主的工作，全力投入募款工作時， 這樣的困境，是那一類型的專業自主困境？', '["資源分配不足", "案主權益和機構利益衝突", "雙重忠誠度", "科層決策的困境"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
